import{_ as t,o as r,c as i,a2 as o}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Guide de Publication","description":"","frontmatter":{"title":"Guide de Publication"},"headers":[],"relativePath":"docs/fr/publishers/sponsored-social/guide.md","filePath":"docs/fr/publishers/sponsored-social/guide.md"}'),a={name:"docs/fr/publishers/sponsored-social/guide.md"};function n(s,e,d,u,p,l){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="guide-de-publication-tagging" tabindex="-1">Guide de Publication &amp; Tagging <a class="header-anchor" href="#guide-de-publication-tagging" aria-label="Permalink to &quot;Guide de Publication &amp; Tagging&quot;">​</a></h1><p>Pour que l&#39;Annonceur puisse payer la diffusion, vous devez impérativement activer les options de partenariat lors de la publication.</p><div class="tip custom-block"><p class="custom-block-title">Pourquoi ces étapes sont obligatoires ?</p><p>Quand vous cochez &quot;Autoriser le partenaire à booster&quot;, l&#39;annonceur peut diffuser votre contenu comme une publicité depuis son propre compte (sans le republier). Sans cette autorisation, <strong>la campagne ne peut pas démarrer</strong> et <strong>votre rémunération est bloquée</strong>.</p></div><hr><h2>Sur Instagram (Partnership Ads)</h2><div style="border-left:4px solid var(--gi-tint-red-text);padding-left:20px;"><div style="margin-bottom:20px;"><h3>1. Préparez le post</h3><p>Créez votre Post ou Reel normalement. Arrivez à l&#39;étape finale (juste avant de cliquer sur &quot;Partager&quot;).</p></div><div style="margin-bottom:20px;"><h3>2. Paramètres Avancés</h3><p>Descendez tout en bas et cliquez sur <strong>&quot;Paramètres avancés&quot;</strong>.</p></div><div style="margin-bottom:20px;"><h3>3. Ajouter le label</h3><p>Activez l&#39;option <strong>&quot;Ajouter un label Partenariat rémunéré&quot;</strong>.</p></div><div style="margin-bottom:20px;"><h3>4. Identifier la marque</h3><p>Cliquez sur <strong>&quot;Ajouter des partenaires de marque&quot;</strong> et recherchez le nom du compte de l&#39;Annonceur (indiqué dans le brief).</p></div><div style="background:var(--gi-tint-red-bg);border:1px dashed var(--gi-tint-red-text);padding:15px;border-radius:8px;"><h3 class="text-red-200">⚠️ ÉTAPE CRITIQUE</h3><p>Vous devez absolument activer l&#39;option :<br><strong>&quot;Autoriser le partenaire de marque à booster&quot;</strong> (Allow brand partner to boost).</p><p><em>Sans cette case cochée, nous ne pouvons pas lancer la campagne média et votre rémunération peut être bloquée.</em></p></div></div><hr><h2>Sur TikTok (Spark Ads)</h2><div style="border-left:4px solid var(--vp-c-text-1);padding-left:20px;"><div style="margin-bottom:20px;"><h3>1. Paramètres de publicité</h3><p>Publiez la vidéo. Allez dessus, cliquez sur les <strong>3 points (...)</strong> en bas à droite, puis faites défiler jusqu&#39;à <strong>&quot;Paramètres de publicité&quot;</strong> (Ad settings).</p></div><div style="margin-bottom:20px;"><h3>2. Autorisation</h3><p>Activez l&#39;option <strong>&quot;Autorisation de publicité&quot;</strong> (Ad authorization).</p></div><div style="margin-bottom:20px;"><h3>3. Générer le code</h3><p>Cliquez sur <strong>&quot;Générer un code&quot;</strong>, choisissez une durée (30 ou 60 jours) et copiez le code.</p></div><div style="background-color:var(--vp-c-bg-soft);border:1px solid var(--vp-c-divider);padding:15px;border-radius:8px;"><strong>📨 Action finale :</strong><br> Collez ce code dans la messagerie de la campagne sur <a href="https://app.getinside.media/">app.getinside.media</a> pour que l&#39;annonceur puisse lier la vidéo. </div></div><hr><h2>✅ Checklist Avant Publication</h2><div style="border:2px solid var(--gi-tint-green-text);border-radius:8px;padding:20px;background:var(--gi-tint-green-bg);margin-bottom:24px;"><strong style="color:var(--gi-tint-green-text);">Vérifiez chaque point avant de publier :</strong><ul style="margin:0.75rem 0 0;padding-left:1.25rem;"><li style="margin-bottom:0.5rem;"><strong>Instagram :</strong> Label &quot;Partenariat rémunéré&quot; activé + compte annonceur identifié + case &quot;Autoriser le partenaire à booster&quot; cochée</li><li style="margin-bottom:0.5rem;"><strong>TikTok :</strong> Option &quot;Autorisation de publicité&quot; activée + code généré et transmis via la messagerie plateforme</li><li><strong>Les deux :</strong> Publiez, puis confirmez la diffusion sur <a href="https://app.getinside.media/">app.getinside.media</a> pour déclencher le paiement</li></ul></div><h2>Bonnes Pratiques Éditoriales</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;"><strong>Authenticité</strong><p>Utilisez votre ton habituel. Ne jouez pas un rôle, c&#39;est ce que l&#39;Annonceur recherche.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;"><strong>Transparence</strong><p>L&#39;outil de partenariat ajoute automatiquement la mention &quot;Partenariat rémunéré&quot;, ce qui vous met en conformité avec la réglementation française sur la publicité.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;"><strong>Performance</strong><p>Partagez le lien de votre publication avec votre gestionnaire de campagne getinside pour le suivi des performances.</p></div></div>',14)])])}const m=t(a,[["render",n]]);export{g as __pageData,m as default};
